-- ── openHAB ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$openHAB is a free, open-source home automation platform that runs locally on your own hardware and integrates with over 400 technologies to control smart-home devices without relying on the cloud.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Non-profit foundation (openHAB Foundation e.V.) with 200-plus volunteer contributors$q$, company_size),
  headquarters = COALESCE($q$Germany (openHAB Foundation e.V.)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$openHAB Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$openHAB is a free, open-source, privacy-first home automation platform. See its features, pricing, pros and cons, and how it compares to alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$openHAB (open Home Automation Bus) is a vendor- and technology-agnostic, open-source home automation platform started in 2010 by Kai Kreuzer. In 2013 its core functionality was contributed to the Eclipse Foundation as Eclipse SmartHome, and the project is now stewarded by the openHAB Foundation e.V., a registered non-profit association whose mission is to promote free and open-source software in smart-home technology and keep the platform free of commercial lock-in. Written in Java and built on Apache Karaf, openHAB is 100 percent open source and free of charge, with development driven by a community of more than 200 contributors. Its defining differentiator is a local-first, privacy-focused architecture: openHAB runs entirely on the user's own hardware (a Raspberry Pi, NAS, Docker container, or a full server on Linux, macOS, or Windows) and functions without any mandatory cloud service, meaning smart-home data stays on the user's premises. Through a pluggable 'bindings' architecture it connects to more than 400 technologies and thousands of individual devices, spanning protocols like Zigbee, Z-Wave, MQTT, and KNX, as well as commercial ecosystems. A built-in rule engine lets users design automations using time-based and event-based triggers, scripts, notifications, and voice control, and optional cloud connectors allow integration with Google Assistant, Amazon Alexa, and Apple HomeKit for those who want it. openHAB targets DIY smart-home enthusiasts, privacy-conscious homeowners, and system integrators who need a vendor-neutral automation layer that will not be discontinued or paywalled by a single company, distinguishing it from commercial platforms and from home-automation software backed by a single hardware vendor. Its closest open-source alternative is Home Assistant, which has a larger mainstream user base and a more polished onboarding experience, while openHAB is often preferred by users who want deep protocol-level integration flexibility and a foundation-governed, vendor-neutral roadmap. Because there is no company selling openHAB, there are no pricing tiers or paid plans; support comes from the community forum, documentation, and the non-profit openHAB Foundation, which some hardware and software vendors join as paying organizational members to help fund development.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '00ff6895-5fbd-49c5-9a5f-500fdaab2761';

