-- ── OpenKM ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenKM is a Spanish document management and enterprise content management platform offering a free open-source Community Edition alongside paid Professional and Cloud editions with workflow, records management, and support.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Professional and Cloud plans are custom-quoted, with third-party estimates starting around $30/user/month$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$Palma de Mallorca, Spain$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$and multiple other localized languages$q$]::text[],
  seo_title = COALESCE($q$OpenKM Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenKM is a document management and ECM platform with a free open-source edition plus paid Professional and Cloud plans. Compare features, pricing, and pros/cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenKM is a document management system (DMS) and enterprise content management (ECM) platform developed by OpenKM, a Spanish software company headquartered in Palma de Mallorca, Spain. Founded in 2005, the company built its product around an open-source core, and today OpenKM offers three tiers: a free, self-hosted Community Edition released under an open-source license for organizations comfortable with community forum support and no official vendor backing; a paid Professional Edition with vendor support and additional enterprise features, with third-party estimates placing entry pricing around 30 US dollars per user per month; and a Cloud edition aimed at small and mid-sized businesses that want implementation and hosting handled for them, priced on request. OpenKM's core capabilities include document versioning, metadata and taxonomy management, full-text search with OCR, a workflow and business process automation engine built on jBPM, digital signature support, records management (RM) features for regulatory and compliance use cases, and REST APIs plus mobile apps for integration with other business systems. The company has grown an international presence with regional offices and partners across Italy, Poland, Serbia, the Middle East, France, and the United States, while keeping software development centered in its Palma de Mallorca headquarters; it employs roughly 11 to 50 people. OpenKM differentiates itself from larger ECM vendors like OpenText, M-Files, and SharePoint by offering a genuinely free and open-source starting point alongside a self-hosting option, appealing to legal, healthcare, government, and educational organizations that need document control and compliance features without committing to a large SaaS-only contract from day one. Its main tradeoffs are less transparent list pricing for the paid tiers (requiring a sales conversation), an admin interface that some reviewers describe as dated relative to newer cloud-native DMS tools, and no official support for the free Community Edition beyond public forums. It competes with other open-source and semi-open ECM platforms such as Alfresco, Nuxeo, and LogicalDOC, as well as commercial cloud document management tools like Box and DocuWare, for organizations that prioritize on-premises control, records management, and lower total cost of ownership over a fully managed SaaS experience.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '13b061f8-1278-44ee-b96b-21fa24709fc9';

