-- ── OpenMeter ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OpenMeter is a usage metering and billing infrastructure platform for AI and API-based products, offering an open-source self-hosted engine and a managed cloud service now operated as Kong Metering and Billing after Kong's 2025 acquisition.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open-source, self-hosted); managed cloud pricing is custom via Kong sales$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$Now part of Kong Inc. (acquired September 2025); originally an 11-50 employee startup$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, USA (now a subsidiary of Kong Inc.)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OpenMeter Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OpenMeter is open-source usage metering and billing infrastructure for AI and API products, now part of Kong. See features, pricing, and alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OpenMeter is a usage metering and billing infrastructure platform designed for developers building AI, API, and infrastructure products that need usage-based pricing. It was founded in 2023 by Peter Marton and Andras Toth, went through Y Combinator's Winter 2023 batch, and raised roughly 3.12 million dollars in seed funding from investors including Haystack, Sunflower Capital, STRT Holding, and Y Combinator, with headquarters in San Francisco, California. Marton previously worked on Stripe's usage and cost platform and built serverless infrastructure at Netflix, and earlier co-founded RisingStack, a Node.js monitoring company, giving OpenMeter's founding team direct experience with usage-based billing at scale. On September 3, 2025, OpenMeter was acquired by Kong Inc., the API infrastructure company, to power AI and API monetization; the product has since been positioned as 'Kong Metering and Billing' within Kong's Konnect platform, while the underlying open-source metering engine remains available on GitHub under an Apache 2.0 license for self-hosted use. OpenMeter's core capability is converting raw events, logs, and metrics into real-time usage records that can be billed, rate-limited, or used to enforce quotas, including edge-based limit enforcement so usage caps can be applied without added latency. It provides a no-code product catalog for iterating on pricing plans, credits, and commitments without new engineering work, plus revenue insight dashboards that surface expansion and churn signals for sales and finance teams. Developers integrate it via SDKs for TypeScript, Python, and Go, and it connects to existing observability and infrastructure tooling including OpenTelemetry, Kubernetes, LangChain, and PostgreSQL. OpenMeter is particularly suited to AI companies that need to bill customers per token or per API call, SaaS platforms transitioning to usage-based pricing, and infrastructure providers metering compute or storage consumption. Its main alternatives include Metronome, Lago, Orb, and Stripe Billing's usage-based features, with OpenMeter's key differentiators being its open-source self-hosted option and, post-acquisition, deep integration with Kong's existing API gateway and Konnect customer base for companies already using Kong for API management.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2df1bf37-9d52-4951-9c51-d887b5e883c4';

